// 解析预处理行标记，更新当前文件名和行号
void process_line_marker(const std::string& marker) {
  std::istringstream iss(marker);
  char hash;
  iss >> hash; // 读取 '#'

  int lineNum;
  iss >> lineNum;

  std::string filename;
  char quote;
  iss >> quote; // 读取第一个引号
  if (quote == '"') {
    std::getline(iss, filename, '"'); // 读取到下一个引号
  }

  // 更新当前行号和文件名
  if (!filename.empty()) {
    currentFileName = filename;
    lineOffset = lineNum - 1; // 行号偏移
  }
}

