// 解析预处理行标记，更新当前文件名和行号
void process_line_marker(const std::string& marker) {
  // 查找引号包围的文件名
  size_t firstQuote = marker.find('"');
  if (firstQuote == std::string::npos) {
    return; // 没有文件名，可能是系统头文件标记
  }

  size_t secondQuote = marker.find('"', firstQuote + 1);
  if (secondQuote == std::string::npos) {
    return; // 没有结束引号
  }

  std::string filename = marker.substr(firstQuote + 1, secondQuote - firstQuote - 1);

  // 提取行号（#后面的第一个数字）
  size_t numStart = marker.find_first_of("0123456789");
  if (numStart == std::string::npos) {
    return;
  }

  size_t numEnd = marker.find_first_not_of("0123456789", numStart);
  std::string lineNumStr = marker.substr(numStart, numEnd - numStart);
  int lineNum = std::stoi(lineNumStr);

  // 只更新实际源文件的标记（不是系统头文件）
  if (filename.find("<") == std::string::npos) { // 不是 <built-in> 等系统头文件
    currentFileName = filename;
    // 行号偏移 = 标记的行号 - 当前ANTLR行号
    // 我们需要在print_token中计算adjustedLine = token->getLine() + (lineNum - token->getLine())
    // 实际上，lineOffset应该基于第一个实际源文件标记
    static bool firstSourceFile = true;
    if (firstSourceFile) {
      lineOffset = lineNum - 1; // 第一个源文件标记
      firstSourceFile = false;
    }
  }
}

